Skill: retry
Description: Decorator that retries a function with exponential backoff
```python
import functools
import time

def retry(times=3, delay=1.0, backoff=2.0):
    def deco(fn):
        @functools.wraps(fn)
        def wrapper(*args, **kwargs):
            wait = delay
            for attempt in range(times):
                try:
                    return fn(*args, **kwargs)
                except Exception:
                    if attempt == times - 1:
                        raise
                    time.sleep(wait)
                    wait *= backoff
        return wrapper
    return deco
